#include <iostream>

void swapValues(int* ptr1, int* ptr2) {
    int temp = *ptr1;
    *ptr1 = *ptr2;
    *ptr2 = temp;
}

int main() {
    int x = 5;
    int y = 15;
    std::cout << "Initial: x = " << x << ", y = " << y << std::endl;
    swapValues(&x, &y);
    std::cout << "Swapped: x = " << x << ", y = " << y << std::endl;
    return 0;
}
